__global__ void
lud_internal(float *m, 
             float *peri_row,
             float *peri_col,
             int matrix_dim, 
             int offset)
{

    int  bx = blockIdx.x;	
    int  by = blockIdx.y;	

    int  tx = threadIdx.x;
    int  ty = threadIdx.y;

    int i;
    float sum;

    int global_row_id = offset + (by+1)*BLOCK_SIZE;
    int global_col_id = offset + (bx+1)*BLOCK_SIZE;

    peri_row[ty * BLOCK_SIZE + tx] = m[(offset+ty)*matrix_dim+global_col_id+tx];
    peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id+ty)*matrix_dim+offset+tx];

    __syncthreads();

    sum = 0;
    for (i=0; i < BLOCK_SIZE; i++)
        sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
    m[(global_row_id+ty)*matrix_dim+global_col_id+tx] -= sum;


}

void lud_cuda(float *d_m, int matrix_dim) {
    float *d_shadow;
    float *d_dia;
    float *d_peri_row;
    float *d_peri_col;
    size_t shadow_size = BLOCK_SIZE * BLOCK_SIZE * sizeof(float);

    cudaMalloc(&d_shadow, shadow_size);
    cudaMalloc(&d_dia, shadow_size);
    cudaMalloc(&d_peri_row, shadow_size);
    cudaMalloc(&d_peri_col, shadow_size);

    dim3 block(BLOCK_SIZE, 1, 1);
    dim3 block2(BLOCK_SIZE * 2, 1, 1);
    dim3 block3(BLOCK_SIZE, BLOCK_SIZE, 1);

    int i = 0;
    for (i=0; matrix_dim-BLOCK_SIZE > i; i += BLOCK_SIZE) {

        lud_diagonal<<<1, block>>>(d_m, d_shadow, matrix_dim, i);

        int num_blocks = (matrix_dim-i)/BLOCK_SIZE-1;
        if (num_blocks > 0) {
            dim3 grid_peri(num_blocks, 1, 1);
            lud_perimeter<<<grid_peri, block2>>>(d_m, d_dia, d_peri_row, d_peri_col, matrix_dim, i);

            dim3 grid_internal(num_blocks, num_blocks, 1);
            lud_internal<<<grid_internal, block3>>>(d_m, d_peri_row, d_peri_col, matrix_dim, i);
        }
    }

    lud_diagonal<<<1, block>>>(d_m, d_shadow, matrix_dim, i);

    cudaFree(d_shadow);
    cudaFree(d_dia);
    cudaFree(d_peri_row);
    cudaFree(d_peri_col);
}

